INSERT INTO "public"."service" ("id", "service_category_id", "name", "category", "title", "description", "sort_order", "route_path", "app_role_group_id", "app_role_group_uuid", "target_audience", "release_status") VALUES
	('89c10335-ac97-4c7a-b83f-a7f2e51de966', '2f310cc9-454d-4032-8e01-25a493a0a203', '🚀面接後：辞退を未然に防ぐ', NULL, '面接後の「本音」をキャッチし、辞退を未然に防ぐトラッカー', '「面接の感触は良かったのに、なぜ辞退されたのかわからない…」そんな採用のブラックボックスを解消します。
面接終了後、候補者のスマホに約30秒で終わるショートアンケートを自動送信。面接の場では直接言いにくい「懸念点」や「志望度の変化」をリアルタイムに可視化します。', 80, '/adm/pulse', NULL, NULL, 'adm', '公開'),
	('ee5e31ef-60da-4dc2-a200-de50db9009fd', '35c69c7f-6580-4250-a125-d15c28ead6b2', '組織の登録', NULL, '基本設定', '企業の階層構造をシステム上に忠実に再現。部署ごとの親子関係を設定することで、全社からチーム単位まで階層別の集団分析を可能にし、組織の「どこに」課題があるのかを正確に特定するための土台を作ります。', 10, '/adm/divisions', NULL, NULL, 'adm', '公開'),
	('3fd119fa-677c-4a01-8de5-e739e8d862b6', '2f310cc9-454d-4032-8e01-25a493a0a203', '🔔① AI求人・募集文メーカー', NULL, '💫【毎月10回無料】無料媒体からスカウトまで全対応！最適な原稿と戦略をAIで。', '3つの質問に答えるだけで、あなたの会社の「リアルな魅力」が伝わる求人票・スカウト文・面接ガイドをAIが瞬時に作成します。
予算やターゲットに応じた最適な採用プラットフォームの提案もお任せください。', 30, '/adm/recruitment-ai', NULL, NULL, 'adm', '公開'),
	('aff8de3e-685f-4f68-9107-b7bca369eaa5', '2f310cc9-454d-4032-8e01-25a493a0a203', '採用サイト比較ダッシュボード', NULL, '【Proプラン限定】採用市場・競合分析ダッシュボード', '入力された条件をもとに、Web上の求人情報を網羅する検索エンジンをリアルタイムに解析し、日本中の最新データを一括取得。
他社の給与相場や募集条件を可視化し、データに基づいた強い採用戦略を支援します。
', 20, 'market-analysis', NULL, NULL, 'adm', '公開'),
	('6aad78e3-7f6c-4592-855b-8e23d3c25134', '2f310cc9-454d-4032-8e01-25a493a0a203', '🔔➁ AI求人・募集文 【アーカイブ】', NULL, '【Proプラン限定】AI求人原稿のアーカイブ管理', 'AI求人メーカーで作成したすべての履歴を自動で保存します。
過去の質問内容と生成結果をセットで振り返り、採用チーム全体での目線合わせや媒体運用に役立てます。', 40, '/adm/recruitment-ai-log', NULL, NULL, 'adm', '公開'),
	('3a5034ba-06dc-4157-b1bd-351d4bc5c01f', '35c69c7f-6580-4250-a125-d15c28ead6b2', '従業員の登録', NULL, '基本設定', '受検対象となる従業員情報を一括インポートや個別編集で管理。
所属部署や役職、雇用形態、メールアドレスを正確に紐付けることで、自動配信の宛先管理や、属性ごとのきめ細やかなストレス分析の実行を支えます。', 20, '/adm/employees', NULL, NULL, 'adm', '公開'),
	('6ca44518-71ee-4fb3-a520-43509c317f8a', '2c64738f-bee1-458d-afae-67033faeceb0', '高ストレス者一覧（人事用）', NULL, 'ストレスチェック', '高ストレス者への面談勧奨から、オンラインでの申出受付、産業医による就業上の措置の記録までを一気通貫で管理。
機密性の高い医療情報を人事データと分離して保護し、セキュアなフォローアップ体制を構築します。', 15, '/adm/high-stress', NULL, NULL, 'adm', '公開'),
	('63346225-2c85-4ccc-995e-cc68cb3b3272', '2c64738f-bee1-458d-afae-67033faeceb0', '労基署報告用データ集計', NULL, 'ストレスチェック', '労働基準監督署へ提出する年1回の報告書に必要な数値を、データベースから自動集計。
受検者数や面談実施数などの正確な算出を自動化することで、手作業による転記ミスをゼロにし、法令遵守業務を効率化します。', 60, '/adm/gov-report', NULL, NULL, 'adm', '公開'),
	('2eb4f512-4129-4657-8c93-dcffdd04c7db', '194390c5-dafd-482b-b979-60f165b7ae28', '🚀新規ご契約（会社）', NULL, '新規ご契約（会社登録）', '「新規ご契約（会社登録）」、招待メール送信', 10, '/saas_adm/tenants', '74f8e05b-c99d-45ee-b368-fdbe35ee0e52', NULL, 'saas_adm', '公開'),
	('340b1610-665c-48c9-8e64-37755da227c3', '194390c5-dafd-482b-b979-60f165b7ae28', '💡SaaSサービス管理', NULL, 'SaaSサービス機能の管理', '「SaaSサービス機能の登録」、各条件で有効・無効を設定する。', 20, '/system-master', '74f8e05b-c99d-45ee-b368-fdbe35ee0e52', NULL, 'saas_adm', '公開'),
	('1855786d-abb7-4c98-8b43-f33ee7d092cb', '21e56253-84a1-4a80-bbfa-1b15e918c961', '会社登録', NULL, '施工会社（納入先）の一括管理・登録画面', '納入登録や有効期限アラートの基盤となる施工会社情報を管理する画面です。正しいメールアドレスを登録することでアラート機能が正常に動作し、システム統計により登録済みの会社数をリアルタイムで把握可能です。', 30, '/myou/companies', NULL, NULL, 'all_users', '公開'),
	('ecfd2d1d-45e8-4e2a-b465-e24008492d4c', '2c64738f-bee1-458d-afae-67033faeceb0', 'ストレスチェック進捗管理', NULL, 'ストレスチェック', '全従業員の受検状況をリアルタイムで可視化。未受検者へのワンクリック催促メール送信や、実施期間の自動管理により、人事担当者の事務負担を大幅に軽減し、高い受検率の達成を強力にサポートします。', 10, '/adm/stress-check/progress', NULL, NULL, 'adm', '公開'),
	('8ae9c4fd-acd9-4584-b14c-02b31ead0db8', 'fbbd4d45-6610-44ef-9989-3f3183ce3158', '✨ 出荷処理', NULL, 'QRスキャンによる納入登録・製品管理画面', '施工会社を選択後、カメラで製品ラベルのQRコードを読み取ることで、データベースへ自動登録し、製品のトレーサビリティを効率化する操作画面。', 10, '/myou/delivery-scan', NULL, NULL, 'all_users', '公開'),
	('43c556f0-54ad-414e-b808-c46e1563437d', 'dfa11140-e8fa-4740-83ff-6f3432466770', 'ストレスチェック × Echo クロス分析', NULL, 'ストレスチェック + パルスサーベイ', '年1回の「面」の調査と、毎月（Echo）の「線」のパルスサーベイを統合。
ストレスチェックでは良好でも、直近で急激にコンディションが低下した従業員を自動検知し、離職や休職の予兆をいち早くキャッチします。', 20, '/adm/pulse-stress', NULL, NULL, 'adm', '公開'),
	('425579cc-feb9-4c6d-86f6-dccc34b15b6b', '20b94ed3-9847-4761-8497-8cd16363b357', '🔊 お知らせ管理', NULL, '社内通知・お知らせの一括管理と編集画面', '人事担当者が従業員向けのお知らせを一覧表示、新規追加、編集できる管理画面です。公開日や対象範囲の確認に加え、最新情報には「NEW」バッジが表示されるなど、社内情報の円滑な共有と運用をサポートします。', 30, '/adm/announcements', NULL, NULL, 'adm', '公開'),
	('6c776bc8-3672-4a18-91e5-1d995658e5c9', '2c64738f-bee1-458d-afae-67033faeceb0', '組織健康度ダッシュボード', NULL, '組織健康度・分析ダッシュボード', '「ストレスチェック」の結果のダッシュボードです。
全社のコンディションを可視化し、AIがフリーコメントから組織の課題やポジティブな傾向を自動抽出します。
部署別のスコアや要注意アラートにより、経営層や人事が優先的に取り組むべき改善ポイントを即座に特定可能です。', 20, '/adm/survey/dashboard', NULL, NULL, 'adm', '公開'),
	('a1b2c3d4-e5f6-7890-abcd-ef1234567890', '1dc338ff-19d7-407e-94e4-06e60b1339a0', '😀 ストレスチェック', NULL, '💫【毎月10回無料】あなたの心の健康診断（ストレスチェック）', '本調査は、労働安全衛生法に基づく法定検査です。回答内容は法令に基づき厳重に管理され、本人の同意なく事業者（会社側）に結果が提供されたり、回答結果を理由に不利益な取扱いを受けることはありません。現在のありのままの状態をご回答ください。ご自身のストレス状態に気づき、メンタルヘルス不調を未然に防ぐことを目的としています。', 10, '/stress-check', NULL, NULL, 'all_users', '公開'),
	('27bedc98-3223-42e7-94f5-ee4fdfc31d0c', 'fbbd4d45-6610-44ef-9989-3f3183ce3158', '🚀 トレーサビリティ', NULL, ' 流通経路の照会とシリアル番号検索画面', 'シリアル番号やQRスキャンにより、製品の流通履歴を即座に照会できます。ブロックチェーン技術を活用し、改ざん不能なデータで透明性を担保します。', 20, '/myou/traceability', NULL, NULL, 'all_users', '公開'),
	('ae6a59be-b368-4236-b1bc-4c2a7aaf034c', '2c64738f-bee1-458d-afae-67033faeceb0', '組織健康度分析（ヒートマップ）', NULL, 'ストレスチェック', '部署ごとの回答結果を「仕事の負担」や「周囲の支援」などの尺度別に多角的に集計。
全国平均と比較した偏差値や健康リスク値を自動算出し、組織全体の傾向と構造的な課題を客観的なデータで浮き彫りにします。', 40, '/adm/stress-check/group-analysis', NULL, NULL, 'adm', '公開'),
	('68f929d9-3db3-4acf-8ee4-1f38649f493c', 'dfa11140-e8fa-4740-83ff-6f3432466770', 'パルス調査期間管理', NULL, '月次パルス調査の実施期間・期限管理画面', '従業員のコンディションを把握するパルス調査の実施期間や回答期限を設定・管理する画面です。設定したスケジュールはトップ画面の重要タスクに自動表示され、回答漏れを防ぎながら効率的な運用をサポートします。
ポータル画面TOPに「実施ボタン」に表示されます。実施後は表示されません。', 10, '/adm/pulse-survey-periods', NULL, NULL, 'adm', '公開'),
	('ef990d87-47f9-47f1-9d9e-ab5ef1a8e647', '2c64738f-bee1-458d-afae-67033faeceb0', '組織健康度ダッシュボード', NULL, '組織健康度・分析ダッシュボード', '「今月の組織健康度アンケート」の結果のダッシュボードです。
チームごとの健康度スコアや、メンバーのコンディション推移を視覚的に分析できます。
日々のマネジメントや、より良い職場環境をつくるためのアクションにお役立てください。', 100, 'survey/dashboard ', NULL, NULL, 'adm', '公開'),
	('d6717904-7ed3-44cf-bc80-c414832a23b8', '2c64738f-bee1-458d-afae-67033faeceb0', '組織健康度分析（ヒートマップ）', NULL, 'ストレスチェック', '縦軸に部署、横軸に詳細尺度を配したマトリックス形式で表示。ストレスリスクの高い箇所が「赤色」で直感的に判別できるため、経営層への報告資料としてそのまま活用でき、迅速な組織改善アクションを可能にします。', 400, '/adm/stress-check/heat-map', NULL, NULL, 'adm', '公開'),
	('7d3a4972-a822-4a1d-8934-76ad59cf1501', '2f310cc9-454d-4032-8e01-25a493a0a203', '✨② ハローワーク用CSV作成', NULL, '【Proプラン限定】ハローワーク一括登録用CSV出力', '1件ずつ何十分もかけてコピペしていた、ハローワークへの求人登録作業から解放されます。
システム上で作成した求人データを、ハローワーク指定の厳格なフォーマット（HTMLタグ除去・文字化け防止BOM対応済み）に自動変換し、一括登録用のCSVファイルとしてダウンロードできます。
あとは、ハローワークの事業主マイページからファイルを読み込ませるだけで、複数の求人もあっという間に登録完了です。
⏱️ 作業時間を数十分の一に: コピペミスや、文字数オーバーによるエラーを未然に防ぎます。
💡 迷わない安心設計: ダウンロード後のアップロード手順も、画面内のガイドでしっかりサポートします。', 60, '/adm/hellowork', NULL, NULL, 'adm', '公開'),
	('480451a7-c1c9-4262-9555-6376936608d2', '2f310cc9-454d-4032-8e01-25a493a0a203', '👋オファー妥当性検証', NULL, 'AIによるオファー条件の妥当性診断画面', '採用ターゲットの職種や想定給与を入力すると、最新の市場データとAI推論を掛け合わせ、提示オファーの競争力を即座に診断します。データに基づいた客観的な判断により、採用成功率の向上を強力にバックアップします。', 10, '/adm/offer-validation', NULL, NULL, 'adm', '公開'),
	('89fe579d-34b6-43b8-9ccf-5da85728c6dd', '2c64738f-bee1-458d-afae-67033faeceb0', 'AI職場改善提案エージェント', NULL, '職場改善提案の自動生成画面', 'ストレスチェックの集団分析結果をAIが読み取り、具体的な職場改善策を自動生成する画面です。データに基づいた客観的な提案により、人事担当者の負担を軽減しながら、実効性の高い改善計画の策定を支援します。', 30, '/adm/ai-workplace-improvement', NULL, NULL, 'adm', '公開'),
	('73b6b91e-0d90-487f-ab4c-3f4548fd320d', '35c69c7f-6580-4250-a125-d15c28ead6b2', 'ストレスチェック実施期間の管理', NULL, 'ストレスチェックの実施・受検期間管理画面', 'ストレスチェックの実施期間や対象年度、質問数を一括設定・管理する画面です。現在の実施ステータスや期間をリアルタイムで把握でき、新規作成や編集を通じて、法令に準拠した計画的な運用を強力にサポートします。', 40, '/adm/stress-check/mnt_sets', NULL, NULL, 'adm', '公開'),
	('938643e5-c21e-44bf-a4e9-36df00068420', 'beaf010f-4e1c-46aa-9cc0-101f933c9dd8', '高ストレス者フォロー管理（産業医・保健師）', NULL, '高ストレス者の面接指導・就業措置管理画面', '産業医・保健師専用の管理画面で、高ストレス判定者のリスト化や面接予約、実施履歴を一元管理します。適切な就業措置の記録やリマインダー設定が可能で、法令遵守に基づいた迅速なフォロー体制の構築を支援します。', 10, '/adm/high-stress-followup', NULL, NULL, 'adm', '公開'),
	('8eb0bb36-71f6-4b94-a413-d9ae7662a83f', '6f555967-a96d-407a-9446-ad4f3bec8305', '⏰ リモートワーク出退勤の打刻', NULL, '社用端末で安心打刻！テレワーク作業開始・終了の記録管理', '承認済みPCで作業時間を正確に記録。位置情報とPCログを連携し、テレワーク中の稼働状況を可視化します。
テレワークには、「🖥️ リモートワーク申請＆端末登録」で申請し、人事の承認が必要です。', 20, '/remort_work', NULL, NULL, 'all_users', '公開'),
	('039ce8ab-b923-46e6-b93c-c65eff1687b1', '6f555967-a96d-407a-9446-ad4f3bec8305', '🗓️ 私の出退勤カレンダー（ 自己確認用）', NULL, '従業員向け勤怠確認・月次カレンダー画面', 'ログイン中の従業員が自分の出退勤記録を月次カレンダー形式で確認し、総労働時間・残業時間・休日出勤・アラート件数を一目で把握できる画面です。', 30, '/attendance/self', NULL, NULL, 'all_users', '公開'),
	('a2c84aa8-dd1a-4a77-a369-a0a8ec69135e', '6a92a6a9-357a-46ef-81a5-a26bc2f21b64', '労使協定（36（サブロク）協定）時間の設定', NULL, '自社の規定に最適化！残業アラート閾値の個別設定', '月間・年間・平均の残業上限と警告ラインを自社ルールで設定。
 法定労働時間を超えて労働者に時間外労働をさせる場合や法定休⽇に労働させる場合には、
 労働基準法第36条に基づく労使協定（36（サブロク）協定）の締結
 所轄労働基準監督署⻑への届出が必要です。
 36協定では、「時間外労働を⾏う業務の種類」や「時間外労働の上限」などを決めなければなりません。', 40, '/adm/overtime-settings', NULL, NULL, 'adm', '公開'),
